const $=s=>document.querySelector(s), $$=s=>[...document.querySelectorAll(s)];
const state={user:null,data:null,bootstrap:null,scenarioId:null,ws:null,mode:'pan',camera:{x:30,y:30,z:1},path:[],paint:new Map(),drag:null,pointers:new Map(),images:new Map(),selectedCharacter:null,animations:new Map(),objectDraft:null,selectionDraft:null,selectedObjects:new Set(),selectedNpcs:new Set(),visibilityAnimations:new Map(),followCamera:null,viewPublishTimer:null};
const csrf=()=>document.cookie.split('; ').find(x=>x.startsWith('dnd_csrf='))?.split('=')[1]||'';
async function api(path,opt={}){const headers={...(opt.headers||{})};if(opt.body!==undefined&&!(opt.body instanceof FormData))headers['Content-Type']='application/json';if(opt.method&&opt.method!=='GET')headers['X-CSRF-Token']=csrf();const r=await fetch('/api'+path,{...opt,headers});const d=await r.json().catch(()=>({error:'Respuesta inválida'}));if(!r.ok)throw Error(d.error||'Error');return d}
function toast(text){const e=$('#toast');e.textContent=text;e.classList.add('show');clearTimeout(e.t);e.t=setTimeout(()=>e.classList.remove('show'),2500)}
function formData(form){return Object.fromEntries(new FormData(form))}

const dialog=$('#form-dialog'),dialogForm=$('#dialog-form');let dialogResolve=null,dialogFields=[];
function openForm({title,description='',fields=[],submitText='Guardar',danger=false}){if(dialog.open)dialog.close();dialogFields=fields;$('#dialog-title').textContent=title;$('#dialog-description').textContent=description;$('#dialog-description').hidden=!description;$('#dialog-error').textContent='';const wrap=$('#dialog-fields');wrap.innerHTML='';for(const f of fields){const label=document.createElement('label');if(f.type==='checkbox')label.className='check-field';const caption=document.createElement('span');caption.textContent=f.label;let input;if(f.type==='textarea'){input=document.createElement('textarea');input.rows=f.rows||5}else if(f.type==='select'){input=document.createElement('select');for(const option of f.options||[]){const el=document.createElement('option');el.value=option.value;el.textContent=option.label;input.append(el)}}else{input=document.createElement('input');input.type=f.type||'text'}input.name=f.name;if(f.value!==undefined){if(f.type==='checkbox')input.checked=!!f.value;else input.value=f.value}if(f.required)input.required=true;if(f.min!==undefined)input.min=f.min;if(f.max!==undefined)input.max=f.max;if(f.step!==undefined)input.step=f.step;if(f.placeholder)input.placeholder=f.placeholder;if(f.type==='checkbox'){label.append(input,caption)}else{label.append(caption,input)}if(f.help){const help=document.createElement('small');help.textContent=f.help;label.append(help)}wrap.append(label)}$('#dialog-submit').textContent=submitText;$('#dialog-submit').className=danger?'danger-action':'primary';dialog.showModal();requestAnimationFrame(()=>wrap.querySelector('input:not([type=checkbox]),select,textarea')?.focus());return new Promise(resolve=>dialogResolve=resolve)}
function finishDialog(value){if(!dialogResolve)return;const resolve=dialogResolve;dialogResolve=null;dialog.close();resolve(value)}
function installDefaultDialogHandlers(){$('#dialog-cancel').onclick=()=>finishDialog(null);$('#dialog-close').onclick=()=>finishDialog(null);dialog.oncancel=e=>{e.preventDefault();finishDialog(null)};dialogForm.onsubmit=e=>{e.preventDefault();if(!dialogForm.reportValidity())return;const values=Object.fromEntries(new FormData(dialogForm));for(const f of dialogFields)if(f.type==='checkbox')values[f.name]=dialogForm.elements[f.name].checked;finishDialog(values)}}
installDefaultDialogHandlers();

$$('[data-auth-tab]').forEach(b=>b.onclick=()=>{$$('[data-auth-tab]').forEach(x=>x.classList.toggle('active',x===b));$('#login-form').hidden=b.dataset.authTab!=='login';$('#guest-access').hidden=b.dataset.authTab!=='login';$('#register-form').hidden=b.dataset.authTab!=='register'});
$('#register-form [name=role]').onchange=e=>$('#invite-wrap').hidden=e.target.value!=='DM';
$('#login-form').onsubmit=async e=>{e.preventDefault();try{await api('/auth/login',{method:'POST',body:JSON.stringify(formData(e.target))});await start()}catch(x){$('#auth-error').textContent=x.message}};
$('#register-form').onsubmit=async e=>{e.preventDefault();try{await api('/auth/register',{method:'POST',body:JSON.stringify(formData(e.target))});await start()}catch(x){$('#auth-error').textContent=x.message}};
$('#guest-login').onclick=async()=>{const button=$('#guest-login');button.disabled=true;$('#auth-error').textContent='';try{await api('/auth/guest',{method:'POST',body:'{}'});await start()}catch(x){$('#auth-error').textContent=x.message;button.disabled=false}};
$('#logout').onclick=async()=>{await api('/auth/logout',{method:'POST',body:'{}'});location.reload()};

async function start(){const me=await api('/me');if(!me.user){$('#auth').hidden=false;$('#app').hidden=true;return}state.user=me.user;$('#auth').hidden=true;$('#app').hidden=false;$('#user-label').textContent=`${me.user.name} · ${me.user.role}`;document.body.classList.toggle('is-dm',me.user.role==='DM');document.body.classList.toggle('is-guest',me.user.role==='GUEST');$$('.dm-only').forEach(e=>e.hidden=me.user.role!=='DM');$$('.player-only').forEach(e=>e.hidden=me.user.role!=='PLAYER');$('#characters-panel').hidden=me.user.role!=='PLAYER';if(me.user.role==='GUEST'){$('[data-mode="pan"]').hidden=true;$('#zoom-in').hidden=true;$('#zoom-out').hidden=true;$('#zoom-label').hidden=true;$('#empty h2').textContent='Esperando al DM';$('#empty p').textContent='El mapa aparecerá cuando el DM visualice un escenario activo.'}await loadBootstrap();connectWs()}
async function loadBootstrap(){state.bootstrap=await api('/bootstrap');renderSidebar()}
function renderSidebar(){const list=$('#scenario-list');list.innerHTML='';state.bootstrap.scenarios.forEach(s=>{const b=document.createElement('button');b.className='scenario-item'+(s.id===state.scenarioId?' active':'');b.innerHTML=`<span>${esc(s.name)}</span>${s.active?'<span class="dot">●</span>':''}`;b.onclick=()=>openScenario(s.id);list.append(b)});const chars=$('#character-list');chars.innerHTML='';state.bootstrap.characters.forEach(c=>{const b=document.createElement('button');b.textContent=`${c.name} (${c.max_health} PV)`;b.classList.toggle('active',state.selectedCharacter===+c.id);b.onclick=()=>{state.selectedCharacter=+c.id;renderSidebar();toast('Personaje seleccionado')};chars.append(b)})}
$('#new-scenario').onclick=async()=>{const values=await openForm({title:'Crear escenario',description:'Configura el nombre y las dimensiones de la cuadrícula.',submitText:'Crear escenario',fields:[{name:'name',label:'Nombre',required:true,placeholder:'Ej. Bosque encantado'},{name:'width',label:'Ancho de la cuadrícula',type:'number',value:25,min:5,max:60,required:true,help:'Entre 5 y 60 casillas.'},{name:'height',label:'Alto de la cuadrícula',type:'number',value:25,min:5,max:60,required:true,help:'Entre 5 y 60 casillas.'}]});if(!values)return;try{const d=await api('/scenarios',{method:'POST',body:JSON.stringify({campaignId:+state.bootstrap.campaigns[0].id,name:values.name,width:+values.width,height:+values.height})});await loadBootstrap();openScenario(d.id)}catch(e){toast(e.message)}};
$('#new-character').onclick=async()=>{const values=await openForm({title:'Crear personaje',description:'Podrás cambiar su avatar después.',submitText:'Crear personaje',fields:[{name:'name',label:'Nombre del personaje',required:true,placeholder:'Ej. Arannis'},{name:'maxHealth',label:'Puntos de vida máximos',type:'number',value:10,min:1,required:true}]});if(!values)return;try{await api('/characters',{method:'POST',body:JSON.stringify({campaignId:+state.bootstrap.campaigns[0].id,name:values.name,maxHealth:+values.maxHealth})});await loadBootstrap()}catch(e){toast(e.message)}};
const codexDialog=$('#codex-dialog');
$('#codex-close').onclick=()=>codexDialog.close();
const codexStack=[];
$('#codex-back').onclick=()=>codexGoBack();
$('#codex-button').onclick=async()=>{try{await openCodex()}catch(e){toast(e.message)}};
function slug(text){return String(text||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9_-]+/g,'_').replace(/^_+|_+$/g,'')}
function opt(rows,empty='— Sin cambiar —'){return[{value:'',label:empty},...(rows||[]).map(x=>({value:x.id,label:x.name}))]}
async function openCodex(){codexStack.length=0;await renderCodexHome();if(!codexDialog.open)codexDialog.showModal()}
async function renderCodexHome(){$('#codex-back').hidden=true;$('#codex-title').textContent='Codex';const data=await api('/codex/categories'),wrap=$('#codex-content');wrap.innerHTML='<div class="codex-list"></div>';const list=wrap.firstChild;data.categories.forEach(c=>{const row=document.createElement('button');row.type='button';row.className='codex-row';row.innerHTML=`<div><strong>${esc(c.name)}</strong><br><small>${esc(c.description)}</small></div><span class="codex-count">${+c.count}</span>`;row.onclick=()=>openCodexCategory(c);list.append(row)});if(state.user?.role==='DM'){const personalize=document.createElement('button');personalize.className='codex-row';personalize.type='button';personalize.innerHTML='<div><strong>Personalizar</strong><br><small>Buscar por nombre o etiquetas existentes y guardar una copia homebrew modificada.</small></div><span class="codex-count">＋</span>';personalize.onclick=()=>{codexDialog.close();openCustomizeSearch()};list.append(personalize)}}
async function openCodexCategory(category,query=''){codexStack.push({type:'home'});await renderCodexCategory(category,query)}
async function renderCodexCategory(category,query='',searched=false){$('#codex-back').hidden=false;$('#codex-title').textContent=category.name;const wrap=$('#codex-content');wrap.innerHTML='<label><span>Buscar</span><div class="inline-search"><input id="codex-category-search" autocomplete="off" placeholder="Buscar por nombre, descripción, categoría o tag…"><button id="codex-category-submit" type="button">Buscar</button></div><small id="codex-category-help">Mostrando 15 resultados aleatorios al abrir.</small></label><div id="codex-category-results" class="codex-search-results"></div><div id="codex-pagination" class="codex-pagination"></div>';const input=$('#codex-category-search'),help=$('#codex-category-help'),pager=$('#codex-pagination');input.value=query;let didSearch=searched||query.trim()!=='';const render=(data,q,page)=>{const records=data.records||[],res=$('#codex-category-results');res.innerHTML='';pager.innerHTML='';if(data.random)help.textContent='Mostrando 15 resultados aleatorios al abrir.';else help.textContent=`${+data.total} resultado${+data.total===1?'':'s'} encontrado${+data.total===1?'':'s'}.`;records.forEach(r=>{const meta=category.code==='actions'?[r.category_name||'Acción',r.owner_names?`Criatura: ${r.owner_names}`:null,r.spell_level!==null&&r.spell_level!==undefined?`Nivel ${+r.spell_level}`:null,r.magic_school,r.source_name].filter(Boolean).map(esc).join(' · '):[r.type_name,r.subtype_name,r.source_name].filter(Boolean).map(esc).join(' · ');const card=document.createElement('button');card.type='button';card.className='codex-row codex-result-row';card.innerHTML=`<div><strong>${esc(r.name)}</strong><br><small>${meta||esc(category.name)}</small>${r.short_description?`<p class="muted">${esc(r.short_description)}</p>`:''}</div>`;card.onclick=()=>openCodexRecordDetail(category,+r.id,q);res.append(card)});if(!records.length)res.innerHTML='<p class="muted">Sin resultados.</p>';if(!data.random&&+data.pages>1){const prev=document.createElement('button'),next=document.createElement('button'),label=document.createElement('span');prev.type=next.type='button';prev.textContent='Anterior';next.textContent='Siguiente';label.textContent=`Página ${+data.page} de ${+data.pages}`;prev.disabled=+data.page<=1;next.disabled=+data.page>=+data.pages;prev.onclick=()=>load(q,+data.page-1).catch(e=>toast(e.message));next.onclick=()=>load(q,+data.page+1).catch(e=>toast(e.message));pager.append(prev,label,next)}};const load=async(q=input.value.trim(),page=1)=>{if(q===''){if(didSearch){help.textContent='Escribe una búsqueda para ver resultados.';$('#codex-category-results').innerHTML='<p class="muted">Sin resultados. Cierra y vuelve a abrir la categoría para ver otros registros aleatorios.</p>';pager.innerHTML='';return}const data=await api(`/codex/category-records?category=${encodeURIComponent(category.code)}&q=&limit=15`);render(data,'',1);return}didSearch=true;const data=await api(`/codex/category-records?category=${encodeURIComponent(category.code)}&q=${encodeURIComponent(q)}&page=${page}&limit=15`);render(data,q,page)};$('#codex-category-submit').onclick=()=>load(input.value.trim(),1).catch(e=>toast(e.message));input.onkeydown=e=>{if(e.key==='Enter'){e.preventDefault();load(input.value.trim(),1).catch(x=>toast(x.message))}};await load(query.trim(),1);requestAnimationFrame(()=>input.focus())}
async function openCodexRecordDetail(category,id,query){codexStack.push({type:'category',category,query});if(category.code==='actions')await renderCodexActionDetail(category,id,query);else await renderCodexGenericDetail(category,id,query)}
async function renderCodexActionDetail(category,id,query=''){$('#codex-back').hidden=false;const data=await api(`/codex/action?id=${id}`),r=data.record;$('#codex-title').textContent=r.name;const wrap=$('#codex-content');wrap.innerHTML='<label><span>Buscar</span><input id="codex-category-search" autocomplete="off" placeholder="Buscar por nombre, descripción, categoría o tag…"><small>Escribe para volver a resultados de búsqueda.</small></label><div id="codex-category-results" class="codex-search-results"></div>';const input=$('#codex-category-search');input.value=query;input.oninput=()=>renderCodexCategory(category,input.value.trim(),true).catch(e=>toast(e.message));const fields=[['Categoría',r.category_name],['Activación',r.activation_name],['Nivel',r.spell_level!==null&&r.spell_level!==undefined?String(+r.spell_level):null],['Escuela',r.magic_school],['Alcance',r.range_text],['Duración',r.duration_text],['Componentes',r.components_text],['Clases',data.classes?.join(', ')],['Criaturas',data.owners?.join(', ')],['Tags',data.tags?.join(', ')],['Fuente',r.source_name]].filter(x=>x[1]);$('#codex-category-results').innerHTML=`<article class="codex-detail"><h3>${esc(r.name)}</h3><dl>${fields.map(([k,v])=>`<dt>${esc(k)}</dt><dd>${esc(v)}</dd>`).join('')}</dl>${r.description?`<div class="description">${esc(r.description)}</div>`:''}</article>`;requestAnimationFrame(()=>input.focus())}
async function renderCodexGenericDetail(category,id,query=''){$('#codex-back').hidden=false;const data=await api(`/codex/record?category=${encodeURIComponent(category.code)}&id=${id}`),r=data.record,labels=data.labels||{};$('#codex-title').textContent=r.name;const wrap=$('#codex-content');wrap.innerHTML='<label><span>Buscar</span><input id="codex-category-search" autocomplete="off" placeholder="Buscar por nombre, descripción, categoría o tag…"><small>Escribe para volver a resultados de búsqueda.</small></label><div id="codex-category-results" class="codex-search-results"></div>';const input=$('#codex-category-search');input.value=query;input.oninput=()=>renderCodexCategory(category,input.value.trim(),true).catch(e=>toast(e.message));const yn=v=>+v?'Sí':null;const fields=[['Tipo',labels.type||r.background_type_code||r.lineage_type_code||r.hit_die_text||r.subclass_type_text],['Tamaño',labels.size],['Rareza',labels.rarity],['Especie',labels.species],['Trasfondo',labels.background],['Clase',labels.class],['Fuente',r.source_name],['Prerrequisitos',r.prerequisites_text||r.requirements_text],['Competencias',r.skill_proficiencies_text],['Herramientas',r.tool_proficiencies_text],['Idiomas',r.languages_text],['Equipo',r.equipment_text],['Rasgo/feature',r.feature_text],['Características sugeridas',r.suggested_characteristics_text],['Tamaño',r.size_text],['Velocidad',r.speed_text],['Puntuaciones',r.ability_score_text],['Edad',r.age_text],['Alineamiento',r.alignment_text],['Rasgos',r.traits_text],['Beneficios',r.benefits_text],['Daño',r.damage_text],['Propiedades',r.properties_text],['Valor',r.value_text],['Peso',r.weight_text],['Sintonización',yn(r.requires_attunement)],['Mágico',yn(r.is_magical)],['Consumible',yn(r.is_consumable)],['Desafío',r.challenge_rating_text],['Entorno',r.environment_text],['Tags',data.tags?.join(', ')]].filter(x=>x[1]);const primary=data.media?.find(m=>m.purpose==='portrait')||data.media?.[0];const media=primary?`<a class="codex-portrait" href="${esc(primary.url)}" target="_blank" rel="noopener" title="Ver imagen completa"><img src="${esc(primary.url)}" alt="${esc(primary.altText||r.name)}"></a>`:'';$('#codex-category-results').innerHTML=`<article class="codex-detail ${primary?'has-media':''}"><div class="codex-detail-main"><h3>${esc(r.name)}</h3><dl>${fields.map(([k,v])=>`<dt>${esc(k)}</dt><dd>${esc(v)}</dd>`).join('')}</dl>${r.description?`<div class="description">${esc(r.description)}</div>`:''}</div>${media}</article>`;requestAnimationFrame(()=>input.focus())}
async function codexGoBack(){const prev=codexStack.pop();if(!prev)return;if(prev.type==='home')await renderCodexHome();else if(prev.type==='category')await renderCodexCategory(prev.category,prev.query||'')}
async function openCustomizeSearch(){const pick=await openCodexSearchPopup();if(!pick)return;const edit=+pick.record.is_custom===1;const options=await api('/codex/customization/options');const fields=pick.kind==='creature'?creatureCustomFields(pick.record,options,edit):itemCustomFields(pick.record,options,edit);const values=await openForm({title:`${edit?'Editar':'Personalizar'} ${pick.record.name}`,description:edit?'Sobrescribe este registro custom existente.':'Guarda una copia homebrew. El registro base no se modifica.',submitText:edit?'Guardar cambios':'Guardar custom',fields});if(!values)return;const saved=edit?await api(`/codex/customize/${pick.kind}/${+pick.record.id}`,{method:'PATCH',body:JSON.stringify({kind:pick.kind,...values})}):await api('/codex/customize',{method:'POST',body:JSON.stringify({kind:pick.kind,sourceId:+pick.record.id,...values})});toast(edit?`Custom actualizado: ${saved.customIdentifier}`:`Custom guardado: ${saved.customIdentifier}`)}
function openCodexSearchPopup(){return new Promise(resolve=>{if(dialog.open)dialog.close();$('#dialog-title').textContent='Personalizar contenido';$('#dialog-description').textContent='Busca por nombre o etiquetas existentes. La búsqueda usa “contiene”.';$('#dialog-description').hidden=false;$('#dialog-error').textContent='';$('#dialog-submit').textContent='Cerrar';$('#dialog-submit').className='primary';const wrap=$('#dialog-fields');wrap.innerHTML='<label><span>Tipo</span><select id="custom-kind"><option value="creature">Criatura</option><option value="item">Objeto / ítem</option></select></label><label><span>Buscar</span><input id="custom-search" autocomplete="off" placeholder="Ej. goblin, bestia, espada…"><small>Resultados sugeridos automáticamente desde la DB. Se buscará por nombre y tags del material base.</small></label><div id="custom-results" class="codex-search-results"></div>';let timer=null,done=false;const finish=v=>{if(done)return;done=true;dialogResolve=null;dialog.close();installDefaultDialogHandlers();resolve(v)};const search=async()=>{const q=$('#custom-search').value.trim(),kind=$('#custom-kind').value,res=$('#custom-results');res.innerHTML='';if(q.length<2)return;try{const data=await api(`/codex/records?kind=${encodeURIComponent(kind)}&q=${encodeURIComponent(q)}`);data.records.forEach(r=>{const b=document.createElement('button');b.type='button';b.className='codex-row';b.innerHTML=`<div><strong>${esc(r.name)}</strong><br><small>${kind==='creature'?esc(`${r.creature_size_name||''} ${r.creature_type_name||''}`):esc(r.item_type_name||'Objeto')}${r.tag_names?` · Tags: ${esc(r.tag_names)}`:''}</small></div><span class="codex-count">Elegir</span>`;b.onclick=()=>finish({kind,record:r});res.append(b)});if(!data.records.length)res.innerHTML='<p class="muted">Sin resultados.</p>'}catch(e){res.innerHTML=`<p class="error">${esc(e.message)}</p>`}};$('#custom-search').oninput=()=>{clearTimeout(timer);timer=setTimeout(search,250)};$('#custom-kind').onchange=search;dialog.showModal();requestAnimationFrame(()=>$('#custom-search').focus());$('#dialog-cancel').onclick=()=>finish(null);$('#dialog-close').onclick=()=>finish(null);dialog.oncancel=e=>{e.preventDefault();finish(null)};dialogForm.onsubmit=e=>{e.preventDefault();finish(null)}})}
function baseCustomFields(r,edit=false){return[{name:'name',label:'Nombre custom',required:true,value:edit?r.name:`${r.name} Custom`},{name:'customIdentifier',label:'Identificador custom',required:true,value:edit?(r.custom_identifier||`hb_${slug(r.name)}_custom`):`hb_${slug(r.name)}_custom`,help:edit?'Debe seguir siendo único.':'Código único para homebrew, por ejemplo hb_goblin_jefe. Las etiquetas/tags se copian del material base.'},{name:'customTag',label:'Tag custom',value:r.custom_tag||'Homebrew'},{name:'shortDescription',label:'Resumen',value:r.short_description||''},{name:'description',label:'Descripción',type:'textarea',rows:6,value:r.description||''}]}
function creatureCustomFields(r,o,edit=false){return[...baseCustomFields(r,edit),{name:'creatureTypeId',label:'Tipo de criatura',type:'select',options:opt(o.creatureTypes),value:r.creature_type_id||''},{name:'creatureSizeId',label:'Tamaño',type:'select',options:opt(o.creatureSizes),value:r.creature_size_id||''},{name:'armorClassText',label:'Clase de armadura',value:r.armor_class_text||''},{name:'hitPointsText',label:'Puntos de golpe',value:r.hit_points_text||''},{name:'speedText',label:'Velocidad',value:r.speed_text||''},...['strength','dexterity','constitution','intelligence','wisdom','charisma'].map(k=>({name:k,label:{strength:'Fuerza',dexterity:'Destreza',constitution:'Constitución',intelligence:'Inteligencia',wisdom:'Sabiduría',charisma:'Carisma'}[k],type:'number',min:1,max:30,value:r[k]||10})),{name:'challengeRatingText',label:'Challenge Rating',value:r.challenge_rating_text||''},{name:'experiencePoints',label:'Experiencia',type:'number',min:0,value:r.experience_points||''},{name:'traitsText',label:'Rasgos / acciones / notas',type:'textarea',rows:8,value:r.traits_text||''},{name:'equipmentText',label:'Equipo',type:'textarea',rows:3,value:r.equipment_text||''},{name:'environmentText',label:'Entorno',value:r.environment_text||''}]}
function itemCustomFields(r,o,edit=false){return[...baseCustomFields(r,edit),{name:'itemTypeId',label:'Tipo de objeto',type:'select',options:opt(o.itemTypes),value:r.item_type_id||''},{name:'itemRarityId',label:'Rareza',type:'select',options:opt(o.itemRarities),value:r.item_rarity_id||''},{name:'requiresAttunement',label:'Requiere sintonización',type:'checkbox',value:+r.requires_attunement},{name:'isMagical',label:'Es mágico',type:'checkbox',value:+r.is_magical},{name:'isConsumable',label:'Es consumible',type:'checkbox',value:+r.is_consumable},{name:'weightText',label:'Peso',value:r.weight_text||''},{name:'valueText',label:'Valor',value:r.value_text||''},{name:'armorClassText',label:'Clase de armadura',value:r.armor_class_text||''},{name:'damageText',label:'Daño',value:r.damage_text||''},{name:'propertiesText',label:'Propiedades',type:'textarea',rows:4,value:r.properties_text||''},{name:'chargesText',label:'Cargas',value:r.charges_text||''},{name:'resourceCostText',label:'Coste / recurso',value:r.resource_cost_text||''},{name:'requirementsText',label:'Requisitos',type:'textarea',rows:3,value:r.requirements_text||''}]}
$('#menu-btn').onclick=()=>document.body.classList.toggle('menu-open');

function wsUrl(){const configured=$('meta[name=ws-url]').content;if(configured)return configured;return `${location.protocol==='https:'?'wss':'ws'}://${location.hostname}:8081`}
function connectWs(){const ws=new WebSocket(wsUrl());state.ws=ws;ws.onopen=()=>{$('#connection').textContent='online';$('#connection').className='pill online';if(state.scenarioId)subscribe();ws._beat=setInterval(()=>ws.readyState===1&&ws.send(JSON.stringify({action:'heartbeat'})),20000)};ws.onclose=()=>{clearInterval(ws._beat);$('#connection').textContent='offline';$('#connection').className='pill offline';setTimeout(connectWs,2500)};ws.onmessage=async e=>{const m=JSON.parse(e.data);if(m.type==='snapshot'){prepareAnimations(state.data,m.data);state.data=m.data;renderDetails();draw()}else if(m.type==='refresh'&&m.scenarioId===state.scenarioId)subscribe();else if(m.type==='scenarios.changed')await syncScenarioList();else if(m.type==='dm.view.changed')await followDmView(m);else if(m.type==='command.error')toast(m.error);else if(m.type==='error')toast(m.error)}}
async function syncScenarioList(){await loadBootstrap();if(['PLAYER','GUEST'].includes(state.user.role)&&state.scenarioId&&!state.bootstrap.scenarios.some(s=>+s.id===+state.scenarioId)){state.scenarioId=null;state.data=null;state.path=[];$('#workspace').hidden=true;$('#right-panel').hidden=true;$('#empty').hidden=false;$('#empty h2').textContent='Escenario desactivado';$('#empty p').textContent='El DM desactivó este escenario. Elige otro escenario activo.';toast('El escenario fue desactivado')}if(state.user.role==='GUEST'&&state.ws?.readyState===1)state.ws.send(JSON.stringify({action:'guest.view.get'}))}
async function openScenario(id){state.scenarioId=+id;state.path=[];state.selectedObjects.clear();state.selectedNpcs.clear();state.visibilityAnimations.clear();state.followCamera=null;state.camera={x:30,y:state.user.role==='DM'?30-cellSize*5:30,z:1};renderSidebar();document.body.classList.remove('menu-open');$('#empty').hidden=true;$('#workspace').hidden=false;$('#right-panel').hidden=false;resize();if(state.ws?.readyState===1)subscribe();else{try{state.data=await api(`/scenarios/${id}/snapshot`);renderDetails();draw()}catch(e){toast(e.message)}}}
function subscribe(){state.ws.send(JSON.stringify({action:'subscribe',scenarioId:state.scenarioId,camera:sharedCamera()}))}
function sharedCamera(){const r=canvas.getBoundingClientRect(),z=state.camera.z;return{centerX:(r.width/2-state.camera.x)/(cellSize*z),centerY:(r.height/2-state.camera.y)/(cellSize*z),zoom:z}}
function applySharedCamera(camera){if(!camera)return;state.followCamera=camera;const r=canvas.getBoundingClientRect(),z=Math.min(3,Math.max(.25,+camera.zoom||1));state.camera.z=z;state.camera.x=r.width/2-(+camera.centerX||0)*cellSize*z;state.camera.y=r.height/2-(+camera.centerY||0)*cellSize*z;$('#zoom-label').textContent=Math.round(z*100)+'%';draw()}
async function followDmView(message){if(state.user.role!=='GUEST')return;if(!state.bootstrap.scenarios.some(s=>+s.id===+message.scenarioId))await loadBootstrap();if(!state.bootstrap.scenarios.some(s=>+s.id===+message.scenarioId))return;if(+state.scenarioId!==+message.scenarioId)await openScenario(+message.scenarioId);applySharedCamera(message.camera)}
function publishDmView(){if(state.user?.role!=='DM'||!state.scenarioId||!+state.data?.scenario?.active||state.ws?.readyState!==1)return;clearTimeout(state.viewPublishTimer);state.viewPublishTimer=setTimeout(()=>state.ws?.readyState===1&&state.ws.send(JSON.stringify({action:'dm.view',scenarioId:state.scenarioId,camera:sharedCamera()})),80)}
function command(type,payload={}){if(state.ws?.readyState!==1){toast('Sin conexión');return}state.ws.send(JSON.stringify({action:'command',type,requestId:crypto.randomUUID().replaceAll('-',''),payload:{...payload,scenarioId:state.scenarioId}}))}

function renderDetails(){const d=state.data,s=d.scenario;$('#scenario-title').textContent=s.name;$('#scenario-status').textContent=`${s.width}×${s.height} · ${+s.active?'Activo':'Inactivo'}`;$('#toggle-active').textContent=+s.active?'Desactivar':'Activar';$('#turn-info').textContent=d.encounter?`${d.encounter.state} · Ronda ${d.encounter.round_no||0}`:'Sin encounter';const req=$('#movement-requests');req.innerHTML='';d.pendingMovements.forEach(m=>{const x=document.createElement('div');x.className='request';x.innerHTML=`<strong>${esc(m.user_name)}</strong><br><small>${esc(m.reason||'Requiere revisión')}</small><br><button data-a>✓ Aprobar</button><button data-r>✕ Rechazar</button>`;x.querySelector('[data-a]').onclick=()=>command('movement.approve',{movementId:+m.id});x.querySelector('[data-r]').onclick=()=>command('movement.reject',{movementId:+m.id});req.append(x)});if(selectionCount())renderEntitySelection();else draw()}
$('#toggle-active').onclick=async()=>{const active=+state.data.scenario.active;if(active){const accepted=await openForm({title:'Desactivar escenario',description:'Los jugadores saldrán del escenario, pero se conservarán posiciones, vida, iniciativas, notas y el estado del encounter.',submitText:'Desactivar',danger:true,fields:[]});if(!accepted)return}command(active?'scenario.deactivate':'scenario.activate')};
let uploadTarget=null;$('#upload-background').onclick=()=>{uploadTarget='background';$('#image-file').click()};$('#upload-avatar').onclick=()=>{if(!state.selectedCharacter)return toast('Selecciona un personaje');uploadTarget='avatar';$('#image-file').click()};$('#image-file').onchange=async e=>{const file=e.target.files[0];if(!file)return;if(file.size>15*1024*1024){toast('La imagen supera el límite de 15 MB');e.target.value='';return}if(!['image/jpeg','image/png','image/webp'].includes(file.type)){toast('Usa una imagen JPEG, PNG o WebP');e.target.value='';return}try{toast('Subiendo imagen…');const fd=new FormData();fd.append('image',file);const asset=await api('/assets',{method:'POST',body:fd});if(uploadTarget==='background')await api(`/scenarios/${state.scenarioId}/background`,{method:'POST',body:JSON.stringify({assetId:asset.id})});else if(uploadTarget==='avatar')await api(`/characters/${state.selectedCharacter}/avatar`,{method:'POST',body:JSON.stringify({assetId:asset.id})});else if(uploadTarget?.bulkItems)command('tokens.bulk_update',{items:uploadTarget.bulkItems,image_asset_id:asset.id});else if(uploadTarget?.bulkObjectIds)command('objects.bulk_update',{objectIds:uploadTarget.bulkObjectIds,image_asset_id:asset.id});else if(uploadTarget?.kind)command('token.update',{kind:uploadTarget.kind,id:+uploadTarget.id,image_asset_id:asset.id});state.images.clear();await loadBootstrap();subscribe();toast('Imagen actualizada')}catch(x){toast(x.message)}finally{e.target.value=''}};
$('#encounter-prepare').onclick=()=>command('encounter.prepare');$('#encounter-start').onclick=()=>command('encounter.start');$('#encounter-stop').onclick=()=>command('encounter.stop');$('#turn-next').onclick=()=>command('turn.next');$('#order-ties').onclick=async()=>{const ps=state.data.participants;if(!ps.length)return toast('No hay participantes');const values=await openForm({title:'Ordenar iniciativas empatadas',description:'Asigna números menores a quienes deben actuar primero.',submitText:'Aplicar orden',fields:ps.map((p,index)=>({name:`order_${p.id}`,label:`${participantName(p)} · iniciativa ${p.initiative??'sin asignar'}`,type:'number',value:index+1,min:1,required:true}))});if(!values)return;const ids=[...ps].sort((a,b)=>+values[`order_${a.id}`]-+values[`order_${b.id}`]).map(p=>+p.id);command('initiative.reorder_tie',{participantIds:ids})};

const canvas=$('#map'),ctx=canvas.getContext('2d');
function resize(){const r=canvas.getBoundingClientRect(),dpr=devicePixelRatio||1;canvas.width=Math.round(r.width*dpr);canvas.height=Math.round(r.height*dpr);ctx.setTransform(dpr,0,0,dpr,0,0);if(state.user?.role==='GUEST'&&state.followCamera){const z=Math.min(3,Math.max(.25,+state.followCamera.zoom||1));state.camera.z=z;state.camera.x=r.width/2-(+state.followCamera.centerX||0)*cellSize*z;state.camera.y=r.height/2-(+state.followCamera.centerY||0)*cellSize*z}draw()}
new ResizeObserver(resize).observe($('#map-wrap'));
const cellSize=64;
function worldToScreen(x,y){return{x:state.camera.x+x*cellSize*state.camera.z,y:state.camera.y+y*cellSize*state.camera.z}}
function screenToCell(x,y){return{x:Math.floor((x-state.camera.x)/(cellSize*state.camera.z)),y:Math.floor((y-state.camera.y)/(cellSize*state.camera.z))}}
function validCell(c){const s=state.data?.scenario;return s&&c.x>=0&&c.y>=0&&c.x<+s.width&&c.y<+s.height}
function draw(){if(!state.data||!canvas.width)return;const r=canvas.getBoundingClientRect();ctx.clearRect(0,0,r.width,r.height);const s=state.data.scenario,z=state.camera.z,cs=cellSize*z,origin=worldToScreen(0,0);
 if(s.background_asset_id){const img=image(+s.background_asset_id);if(img.complete)ctx.drawImage(img,origin.x,origin.y,+s.width*cs,+s.height*cs)}else{ctx.fillStyle='#201b16';ctx.fillRect(origin.x,origin.y,+s.width*cs,+s.height*cs)}
 ctx.fillStyle='#51302c99';state.data.blocked.forEach(c=>{const p=worldToScreen(+c.x,+c.y);ctx.fillRect(p.x,p.y,cs,cs)});if(state.mode==='path')drawAdjacentCells(cs);ctx.strokeStyle='#77665088';ctx.lineWidth=1;ctx.beginPath();for(let x=0;x<=+s.width;x++){const p=worldToScreen(x,0);ctx.moveTo(p.x,p.y);ctx.lineTo(p.x,origin.y+s.height*cs)}for(let y=0;y<=+s.height;y++){const p=worldToScreen(0,y);ctx.moveTo(p.x,p.y);ctx.lineTo(origin.x+s.width*cs,p.y)}ctx.stroke();if(state.objectDraft)drawObjectDraft(cs);if(state.selectionDraft)drawSelectionDraft(cs);
 state.path.forEach((c,i)=>{const p=worldToScreen(c.x,c.y);ctx.fillStyle='#58aee477';ctx.fillRect(p.x+2,p.y+2,cs-4,cs-4);ctx.fillStyle='white';ctx.font=`${Math.max(10,14*z)}px sans-serif`;ctx.fillText(String(i+1),p.x+5,p.y+17*z)});
 state.data.objects.forEach(object=>drawMapObject({...object,kind:'OBJECT'},cs));const groups=groupTokens();for(const [,tokens] of groups)drawGroup(tokens,cs);drawVisibilityEffects(cs);
}
function objectDraftArea(){if(!state.objectDraft)return null;const a=state.objectDraft.start,b=state.objectDraft.current;return{x:Math.min(a.x,b.x),y:Math.min(a.y,b.y),widthCells:Math.abs(a.x-b.x)+1,heightCells:Math.abs(a.y-b.y)+1}}
function drawObjectDraft(cs){const area=objectDraftArea();if(!area)return;const p=worldToScreen(area.x,area.y);ctx.save();ctx.fillStyle='#d7aa5244';ctx.strokeStyle='#ffd782';ctx.lineWidth=2;ctx.setLineDash([8,5]);ctx.fillRect(p.x,p.y,area.widthCells*cs,area.heightCells*cs);ctx.strokeRect(p.x+1,p.y+1,area.widthCells*cs-2,area.heightCells*cs-2);ctx.setLineDash([]);ctx.fillStyle='#17130fdd';ctx.fillRect(p.x+6,p.y+6,Math.max(62,72*state.camera.z),24);ctx.fillStyle='#fff1c9';ctx.font='bold 13px sans-serif';ctx.fillText(`${area.widthCells} × ${area.heightCells}`,p.x+12,p.y+23);ctx.restore()}
function selectionDraftArea(){if(!state.selectionDraft)return null;const a=state.selectionDraft.start,b=state.selectionDraft.current;return{x:Math.min(a.x,b.x),y:Math.min(a.y,b.y),widthCells:Math.abs(a.x-b.x)+1,heightCells:Math.abs(a.y-b.y)+1}}
function drawSelectionDraft(cs){const area=selectionDraftArea();if(!area)return;const p=worldToScreen(area.x,area.y);ctx.save();ctx.fillStyle='#66aaff28';ctx.strokeStyle='#8bc5ff';ctx.lineWidth=2;ctx.setLineDash([6,4]);ctx.fillRect(p.x,p.y,area.widthCells*cs,area.heightCells*cs);ctx.strokeRect(p.x+1,p.y+1,area.widthCells*cs-2,area.heightCells*cs-2);ctx.restore()}
function drawMapObject(t,cs,alpha=1){ctx.save();ctx.globalAlpha*=alpha;const selected=state.selectedObjects.has(+t.id),widthCells=Math.max(1,+t.width_cells||1),heightCells=Math.max(1,+t.height_cells||1),visualWidth=Math.max(.25,widthCells-.75),visualHeight=Math.max(.25,heightCells-.75),p=worldToScreen(+t.x+.375,+t.y+.375),width=visualWidth*cs,height=visualHeight*cs,img=t.image_asset_id?image(+t.image_asset_id):null;ctx.fillStyle='#b88d52';ctx.fillRect(p.x,p.y,width,height);if(img?.complete&&img.naturalWidth){ctx.save();ctx.beginPath();ctx.rect(p.x,p.y,width,height);ctx.clip();ctx.drawImage(img,p.x,p.y,width,height);ctx.restore()}ctx.strokeStyle=selected?'#fff19b':'#e0b66f';ctx.lineWidth=selected?Math.max(3,cs*.06):Math.max(1,cs*.025);ctx.strokeRect(p.x,p.y,width,height);ctx.restore()}
function groupTokens(){const m=new Map(),push=(t)=>{const k=`${Math.floor(t.renderX??t.x)},${Math.floor(t.renderY??t.y)}`;(m.get(k)||m.set(k,[]).get(k)).push(t)};state.data.npcs.forEach(x=>push({...x,kind:'NPC'}));state.data.players.filter(x=>+x.placed||state.user.role==='DM').forEach(x=>{const pos=animatedPos(x);push({...x,kind:'PLAYER',renderX:pos.x,renderY:pos.y})});return m}
function drawGroup(ts,cs){const base=worldToScreen(+(ts[0].renderX??ts[0].x),+(ts[0].renderY??ts[0].y)),many=ts.length>=4,shown=many?[ts[0]]:ts;shown.forEach((t,i)=>{const cols=ts.length>1?2:1,row=Math.floor(i/cols),col=i%cols,size=(t.kind==='OBJECT'?.25:(t.kind==='NPC'?.98:.48))*cs*(ts.length>1?.72:1),cx=base.x+cs*(ts.length===1?.5:(.28+.44*col)),cy=base.y+cs*(ts.length===1?.5:(.28+.44*row));const current=isCurrent(t),selected=t.kind==='NPC'&&state.selectedNpcs.has(+t.id);if(current){ctx.beginPath();ctx.arc(cx,cy,size*.8,0,Math.PI*2);ctx.fillStyle='#ffd24c88';ctx.fill()}const img=t.image_asset_id?image(+t.image_asset_id):null;if(t.kind==='OBJECT'){ctx.fillStyle='#b88d52';ctx.fillRect(cx-size/2,cy-size/2,size,size);if(img?.complete&&img.naturalWidth){ctx.save();ctx.beginPath();ctx.rect(cx-size/2,cy-size/2,size,size);ctx.clip();ctx.drawImage(img,cx-size/2,cy-size/2,size,size);ctx.restore()}ctx.strokeStyle='#e0b66f';ctx.lineWidth=Math.max(1,cs*.025);ctx.strokeRect(cx-size/2,cy-size/2,size,size)}else{ctx.beginPath();ctx.arc(cx,cy,size/2,0,Math.PI*2);ctx.fillStyle=t.kind==='PLAYER'?'#4c8cc7':'#a04f4f';ctx.fill();ctx.save();ctx.clip();if(img?.complete&&img.naturalWidth){const imgScale=t.kind==='NPC'?1.35:1,imgSize=size*imgScale;ctx.drawImage(img,cx-imgSize/2,cy-imgSize/2,imgSize,imgSize)}ctx.restore();if(selected){ctx.strokeStyle='#fff19b';ctx.lineWidth=Math.max(3,cs*.06);ctx.beginPath();ctx.arc(cx,cy,size*.62,0,Math.PI*2);ctx.stroke()}if(+t.health<=0&&state.user.role==='DM'){ctx.strokeStyle='#ff2222';ctx.lineWidth=3;ctx.beginPath();ctx.moveTo(cx-size/3,cy-size/3);ctx.lineTo(cx+size/3,cy+size/3);ctx.moveTo(cx+size/3,cy-size/3);ctx.lineTo(cx-size/3,cy+size/3);ctx.stroke()}}});if(many){ctx.fillStyle='#111';ctx.beginPath();ctx.arc(base.x+cs*.72,base.y+cs*.28,cs*.18,0,Math.PI*2);ctx.fill();ctx.fillStyle='white';ctx.textAlign='center';ctx.textBaseline='middle';ctx.font=`bold ${Math.max(10,cs*.2)}px sans-serif`;ctx.fillText(String(ts.length),base.x+cs*.72,base.y+cs*.28);ctx.textAlign='start';ctx.textBaseline='alphabetic'}}
function drawVisibilityEffects(cs){if(!['PLAYER','GUEST'].includes(state.user?.role)||!state.visibilityAnimations.size)return;const now=performance.now();let active=false;for(const [key,a] of state.visibilityAnimations){const progress=Math.min(1,(now-a.start)/a.duration);if(progress>=1){state.visibilityAnimations.delete(key);continue}active=true;if(a.type==='disappear'){const alpha=1-progress;if(a.kind==='OBJECT')drawMapObject({...a.entity,kind:'OBJECT'},cs,alpha);else drawNpcGhost(a.entity,cs,alpha)}drawVisibilityHighlight(a,cs,progress)}if(active)requestAnimationFrame(draw)}
function drawNpcGhost(t,cs,alpha){const p=worldToScreen(+t.x+.5,+t.y+.5),size=.98*cs,img=t.image_asset_id?image(+t.image_asset_id):null;ctx.save();ctx.globalAlpha=alpha;ctx.beginPath();ctx.arc(p.x,p.y,size/2,0,Math.PI*2);ctx.fillStyle='#a04f4f';ctx.fill();ctx.clip();if(img?.complete&&img.naturalWidth){const imgSize=size*1.35;ctx.drawImage(img,p.x-imgSize/2,p.y-imgSize/2,imgSize,imgSize)}ctx.restore()}
function drawVisibilityHighlight(a,cs,progress){const pulse=.5+.5*Math.sin(progress*Math.PI*8),alpha=(1-progress)*(.45+.45*pulse),expand=(a.type==='appear'?progress:1-progress)*cs*.22;ctx.save();ctx.globalAlpha=alpha;ctx.strokeStyle=a.type==='appear'?'#fff36b':'#ff9b55';ctx.lineWidth=Math.max(3,cs*.07);ctx.shadowColor=ctx.strokeStyle;ctx.shadowBlur=18;if(a.kind==='OBJECT'){const w=Math.max(1,+a.entity.width_cells||1),h=Math.max(1,+a.entity.height_cells||1),visualW=Math.max(.25,w-.75)*cs,visualH=Math.max(.25,h-.75)*cs,p=worldToScreen(+a.entity.x+.375,+a.entity.y+.375);ctx.strokeRect(p.x-expand,p.y-expand,visualW+expand*2,visualH+expand*2)}else{const p=worldToScreen(+a.entity.x+.5,+a.entity.y+.5);ctx.beginPath();ctx.arc(p.x,p.y,.38*cs+expand,0,Math.PI*2);ctx.stroke()}ctx.restore()}
function isAdjacent(a,b){const dx=Math.abs(+a.x-+b.x),dy=Math.abs(+a.y-+b.y);return Math.max(dx,dy)===1}
function drawAdjacentCells(cs){const own=state.data.players.find(p=>+p.user_id===+state.user.id&&+p.placed);if(!own)return;const anchor=state.path.at(-1)||{x:+own.x,y:+own.y};ctx.fillStyle='#56c87835';for(let dy=-1;dy<=1;dy++)for(let dx=-1;dx<=1;dx++){if(!dx&&!dy)continue;const c={x:+anchor.x+dx,y:+anchor.y+dy};if(!validCell(c))continue;const p=worldToScreen(c.x,c.y);ctx.fillRect(p.x+2,p.y+2,cs-4,cs-4)}}
function prepareAnimations(oldData,newData){prepareVisibilityAnimations(oldData,newData);if(!oldData||+oldData.scenario?.id!==+newData.scenario?.id)return;for(const p of newData.players){const old=oldData.players.find(x=>+x.id===+p.id);if(!old||(+old.x===+p.x&&+old.y===+p.y))continue;let path=[];try{path=typeof p.last_path==='string'?JSON.parse(p.last_path):(p.last_path||[])}catch{}if(path.length)state.animations.set(+p.id,{points:[{x:+old.x,y:+old.y},...path.map(c=>({x:+c.x,y:+c.y}))],start:performance.now(),step:220})}if(state.animations.size)requestAnimationFrame(draw)}
function prepareVisibilityAnimations(oldData,newData){if(!['PLAYER','GUEST'].includes(state.user?.role)||!oldData||+oldData.scenario?.id!==+newData.scenario?.id)return;const now=performance.now();for(const [kind,oldList,newList] of [['OBJECT',oldData.objects,newData.objects],['NPC',oldData.npcs,newData.npcs]]){const oldIds=new Set(oldList.map(x=>+x.id)),newIds=new Set(newList.map(x=>+x.id));for(const entity of newList)if(!oldIds.has(+entity.id))state.visibilityAnimations.set(`${kind}:${entity.id}`,{kind,type:'appear',entity,start:now,duration:1500});for(const entity of oldList)if(!newIds.has(+entity.id))state.visibilityAnimations.set(`${kind}:${entity.id}`,{kind,type:'disappear',entity,start:now,duration:1100})}if(state.visibilityAnimations.size)requestAnimationFrame(draw)}
function animatedPos(t){const a=state.animations.get(+t.id);if(!a)return{x:+t.x,y:+t.y};const elapsed=performance.now()-a.start,index=Math.floor(elapsed/a.step),f=(elapsed%a.step)/a.step;if(index>=a.points.length-1){state.animations.delete(+t.id);return{x:+t.x,y:+t.y}}const from=a.points[index],to=a.points[index+1];requestAnimationFrame(draw);return{x:from.x+(to.x-from.x)*f,y:from.y+(to.y-from.y)*f}}
function isCurrent(t){const e=state.data.encounter;if(!e?.current_participant_id)return false;const p=state.data.participants.find(x=>+x.id===+e.current_participant_id);return p&&p.actor_type===t.kind&&+p.actor_id===+t.id}
function image(id){if(!state.images.has(id)){const i=new Image();i.onload=draw;i.src=`/api/assets/${id}`;state.images.set(id,i)}return state.images.get(id)}

$$('[data-mode]').forEach(b=>b.onclick=()=>setMode(b.dataset.mode));function setMode(m){state.mode=m;state.objectDraft=null;state.selectionDraft=null;$$('[data-mode]').forEach(x=>x.classList.toggle('active',x.dataset.mode===m));if(m!=='path')state.path=[];if(m==='object')toast('Arrastra sobre el mapa para definir el área del objeto');if(m==='select')toast('Arrastra para seleccionar varios objetos; Shift o Ctrl los agrega');draw()}
$('#zoom-in').onclick=()=>zoomAt(1.2,canvas.clientWidth/2,canvas.clientHeight/2);$('#zoom-out').onclick=()=>zoomAt(1/1.2,canvas.clientWidth/2,canvas.clientHeight/2);
function zoomAt(f,x,y){if(state.user?.role==='GUEST')return;const old=state.camera.z,n=Math.min(3,Math.max(.25,old*f));state.camera.x=x-(x-state.camera.x)*n/old;state.camera.y=y-(y-state.camera.y)*n/old;state.camera.z=n;$('#zoom-label').textContent=Math.round(n*100)+'%';draw();publishDmView()}
canvas.addEventListener('wheel',e=>{e.preventDefault();const r=canvas.getBoundingClientRect();zoomAt(e.deltaY<0?1.12:1/1.12,e.clientX-r.left,e.clientY-r.top)},{passive:false});
canvas.onpointerdown=e=>{const forcePan=e.button===1;if(forcePan)e.preventDefault();canvas.setPointerCapture(e.pointerId);state.pointers.set(e.pointerId,{x:e.offsetX,y:e.offsetY});if(state.pointers.size===1){state.drag={x:e.offsetX,y:e.offsetY,cx:state.camera.x,cy:state.camera.y,moved:false,forcePan};if(!forcePan&&state.mode==='object'){const cell=screenToCell(e.offsetX,e.offsetY);if(validCell(cell)){state.objectDraft={start:cell,current:cell};draw()}}else if(!forcePan&&state.mode==='select'&&state.user.role==='DM'){const cell=screenToCell(e.offsetX,e.offsetY);if(validCell(cell)){state.selectionDraft={start:cell,current:cell,additive:e.shiftKey||e.ctrlKey||e.metaKey};draw()}}}if(forcePan)canvas.classList.add('grabbing');if(!forcePan&&['block','unblock'].includes(state.mode))paintAt(e.offsetX,e.offsetY)};
canvas.addEventListener('auxclick',e=>{if(e.button===1)e.preventDefault()});
canvas.onpointermove=e=>{if(!state.pointers.has(e.pointerId))return;state.pointers.set(e.pointerId,{x:e.offsetX,y:e.offsetY});if(state.pointers.size===2){state.objectDraft=null;state.selectionDraft=null;if(state.drag)state.drag.moved=true;const ps=[...state.pointers.values()];if(!state.pinch)state.pinch={d:Math.hypot(ps[0].x-ps[1].x,ps[0].y-ps[1].y),z:state.camera.z};else{const d=Math.hypot(ps[0].x-ps[1].x,ps[0].y-ps[1].y),mid={x:(ps[0].x+ps[1].x)/2,y:(ps[0].y+ps[1].y)/2};zoomAt((state.pinch.z*d/state.pinch.d)/state.camera.z,mid.x,mid.y)}return}if(state.drag){const dx=e.offsetX-state.drag.x,dy=e.offsetY-state.drag.y;if(Math.hypot(dx,dy)>5)state.drag.moved=true;if(state.drag.forcePan||state.mode==='pan'){if(state.user.role!=='GUEST'){state.camera.x=state.drag.cx+dx;state.camera.y=state.drag.cy+dy;draw();publishDmView()}}else if(state.mode==='object'&&state.objectDraft){const cell=screenToCell(e.offsetX,e.offsetY);if(validCell(cell)){state.objectDraft.current=cell;draw()}}else if(state.mode==='select'&&state.selectionDraft){const cell=screenToCell(e.offsetX,e.offsetY);if(validCell(cell)){state.selectionDraft.current=cell;draw()}}else if(['block','unblock'].includes(state.mode))paintAt(e.offsetX,e.offsetY)}};
canvas.onpointerup=e=>{const was=state.drag,draft=state.objectDraft,selection=state.selectionDraft;state.pointers.delete(e.pointerId);if(state.pointers.size<2)state.pinch=null;if(was?.forcePan){canvas.classList.remove('grabbing')}else if(e.type==='pointercancel'){state.objectDraft=null;state.selectionDraft=null;draw()}else if(draft&&state.mode==='object'){const area=objectDraftArea();state.objectDraft=null;draw();if(area)void createObjectArea(area)}else if(selection&&state.mode==='select'){const area=selectionDraftArea();state.selectionDraft=null;if(was?.moved&&area)selectEntitiesInArea(area,selection.additive);else{draw();tap(e.offsetX,e.offsetY,{additive:e.shiftKey||e.ctrlKey||e.metaKey})}}else if(['block','unblock'].includes(state.mode)&&state.paint.size){command('map.cells.paint',{cells:[...state.paint.values()],blocked:state.mode==='block'});state.paint.clear()}else if(was&&!was.moved)tap(e.offsetX,e.offsetY,{additive:e.shiftKey||e.ctrlKey||e.metaKey});if(!state.pointers.size)state.drag=null};canvas.onpointercancel=canvas.onpointerup;
function paintAt(x,y){const c=screenToCell(x,y);if(validCell(c)){state.paint.set(`${c.x},${c.y}`,c);const exists=state.data.blocked.some(b=>+b.x===c.x&&+b.y===c.y);if(state.mode==='block'&&!exists)state.data.blocked.push(c);if(state.mode==='unblock'&&exists)state.data.blocked=state.data.blocked.filter(b=>+b.x!==c.x||+b.y!==c.y);draw()}}
function tap(x,y,options={}){
 const c=screenToCell(x,y);if(!validCell(c))return;
 if(state.moveToken){const t=state.moveToken;state.moveToken=null;command('token.move_dm',{kind:t.kind,id:+t.id,...c});return}
 if(state.mode==='path'){
  const own=state.data.players.find(p=>+p.user_id===+state.user.id&&+p.placed);if(!own){toast('Primero coloca tu personaje en el escenario');return}
  const last=state.path.at(-1);if(last&&last.x===c.x&&last.y===c.y){state.path.pop();draw();return}
  const anchor=last||{x:+own.x,y:+own.y};if(!isAdjacent(anchor,c)){toast('Solo puedes seleccionar una casilla adyacente');return}
  state.path.push(c);draw();return
 }
 if(state.mode==='place'){if(!state.selectedCharacter){toast('Selecciona un personaje');return}command('player.place',{characterId:state.selectedCharacter,...c});setMode('pan');return}
 if(state.user.role!=='DM')return
 if(state.mode==='npc'){void createNpcAt(c);return}
 if(state.mode==='object')return
 const tokens=tokensAtCell(c);if(tokens.length===1)selectMapEntity(tokens[0],!!options.additive);else if(tokens.length>1)showCellMenu(tokens,x,y,!!options.additive);else if(state.user.role==='DM'&&state.mode==='select'){if(selectionCount()){clearEntitySelection();return}void editCellNote(c)}
}
async function createNpcAt(c){const values=await openNpcCreatePopup(c);if(!values)return;command('npc.create',{...c,name:values.name,health:+values.health,armorClass:values.armorClass===''?null:+values.armorClass,initiative:values.initiative===''?null:+values.initiative,visible:values.visible,notes:values.notes,codexCreatureId:values.codexCreatureId||null})}
function openNpcCreatePopup(c){return new Promise(resolve=>{if(dialog.open)dialog.close();let selectedCreature=null,timer=null,done=false;$('#dialog-title').textContent='Agregar personaje del DM';$('#dialog-description').textContent=`Casilla ${c.x+1}, ${c.y+1}. Puedes buscar una criatura del Codex para usar su nombre y token.`;$('#dialog-description').hidden=false;$('#dialog-error').textContent='';$('#dialog-submit').textContent='Agregar NPC';$('#dialog-submit').className='primary';const wrap=$('#dialog-fields');wrap.innerHTML='<label><span>Buscar criatura del Codex</span><div class="inline-search"><input id="npc-creature-search" autocomplete="off" placeholder="Buscar por nombre, tipo, tag…"><button id="npc-creature-clear" type="button">Limpiar</button></div><small id="npc-creature-help">Opcional. Busca con “contiene”; incluye criaturas custom.</small></label><div id="npc-creature-results" class="codex-search-results"></div><p id="npc-creature-picked" class="muted"></p><label><span>Nombre</span><input name="name" value="NPC" required></label><label><span>Puntos de vida</span><input name="health" type="number" value="10" required></label><label><span>Clase de armadura</span><input name="armorClass" type="number" placeholder="Sin CA"></label><label><span>Iniciativa (opcional)</span><input name="initiative" type="number" placeholder="Sin iniciativa"></label><label class="check-field"><input name="visible" type="checkbox" checked><span>Visible para los jugadores</span></label><label><span>Notas privadas</span><textarea name="notes" rows="6" placeholder="Información que solo verá el DM"></textarea></label>';const finish=v=>{if(done)return;done=true;dialogResolve=null;dialog.close();installDefaultDialogHandlers();resolve(v)};const search=async()=>{const q=$('#npc-creature-search').value.trim(),res=$('#npc-creature-results'),help=$('#npc-creature-help');res.innerHTML='';if(q.length<2){help.textContent='Escribe al menos 2 caracteres para buscar.';return}help.textContent='Buscando…';try{const data=await api(`/codex/category-records?category=creatures&q=${encodeURIComponent(q)}&page=1&limit=15`);help.textContent=`${+data.total} resultado${+data.total===1?'':'s'} encontrado${+data.total===1?'':'s'}.`;for(const r of data.records||[]){const b=document.createElement('button');b.type='button';b.className='codex-row';const meta=[r.type_name,r.subtype_name,r.source_name].filter(Boolean).map(esc).join(' · ');b.innerHTML=`<div><strong>${esc(r.name)}</strong><br><small>${meta}</small>${r.short_description?`<p class="muted">${esc(r.short_description)}</p>`:''}</div><span class="codex-count">Elegir</span>`;b.onclick=()=>{selectedCreature=r;dialogForm.elements.name.value=r.name;const n=v=>{const m=String(v||'').match(/\d+/);return m?m[0]:''};const hp=n(r.hit_points_text),ac=n(r.armor_class_text);if(hp)dialogForm.elements.health.value=hp;if(ac)dialogForm.elements.armorClass.value=ac;$('#npc-creature-picked').textContent=`Seleccionado: ${r.name}. PV${hp?`: ${hp}`:''}${ac?` · CA: ${ac}`:''}. El NPC usará el token/retrato de esta criatura si existe.`;res.innerHTML=''};res.append(b)}if(!data.records?.length)res.innerHTML='<p class="muted">Sin resultados.</p>'}catch(e){help.textContent='Error de búsqueda';res.innerHTML=`<p class="error">${esc(e.message)}</p>`}};$('#npc-creature-search').oninput=()=>{clearTimeout(timer);timer=setTimeout(search,250)};$('#npc-creature-search').onkeydown=e=>{if(e.key==='Enter'){e.preventDefault();clearTimeout(timer);search()}};$('#npc-creature-clear').onclick=()=>{selectedCreature=null;$('#npc-creature-search').value='';$('#npc-creature-results').innerHTML='';$('#npc-creature-picked').textContent='';$('#npc-creature-help').textContent='Opcional. Busca con “contiene”; incluye criaturas custom.'};dialog.showModal();requestAnimationFrame(()=>$('#npc-creature-search').focus());$('#dialog-cancel').onclick=()=>finish(null);$('#dialog-close').onclick=()=>finish(null);dialog.oncancel=e=>{e.preventDefault();finish(null)};dialogForm.onsubmit=e=>{e.preventDefault();if(!dialogForm.reportValidity())return;const values=Object.fromEntries(new FormData(dialogForm));values.visible=dialogForm.elements.visible.checked;values.codexCreatureId=selectedCreature?+selectedCreature.id:null;finish(values)}})}
async function createObjectArea(area){const visualWidth=Math.max(.25,area.widthCells-.75),visualHeight=Math.max(.25,area.heightCells-.75);const values=await openForm({title:'Agregar objeto',description:`Área dibujada: ${area.widthCells} × ${area.heightCells} casillas. Tamaño visual: ${visualWidth} × ${visualHeight} casillas.`,submitText:'Agregar objeto',fields:[{name:'name',label:'Nombre',value:'Objeto',required:true},{name:'visible',label:'Visible para los jugadores',type:'checkbox',value:true},{name:'notes',label:'Notas privadas',type:'textarea',rows:6,placeholder:'Descripción, contenido o información para el DM'}]});if(!values)return;command('object.create',{x:area.x,y:area.y,widthCells:area.widthCells,heightCells:area.heightCells,name:values.name,visible:values.visible,notes:values.notes})}
async function editCellNote(c){const current=state.data.cellNotes.find(n=>+n.x===c.x&&+n.y===c.y)?.notes||'';const values=await openForm({title:'Nota de casilla',description:`Casilla ${c.x+1}, ${c.y+1}. Esta nota solo es visible para el DM.`,submitText:'Guardar nota',fields:[{name:'notes',label:'Notas',type:'textarea',rows:8,value:current,placeholder:'Escribe información sobre esta casilla…'}]});if(values)command('cell.note',{...c,notes:values.notes})}
$('#apply-path').onclick=()=>{if(!state.path.length)return toast('Selecciona un camino');command('movement.submit',{path:state.path});state.path=[];draw()};$('#place-character').onclick=()=>{if(!state.selectedCharacter)return toast('Selecciona un personaje en el menú');setMode('place');toast('Toca una casilla')};$('#delay-turn').onclick=async()=>{const options=state.data.participants.filter(p=>+p.id!==+state.data.encounter?.current_participant_id);if(!options.length)return toast('No hay objetivo disponible');const values=await openForm({title:'Retrasar turno',description:'Tu turno se activará cuando el participante seleccionado termine, muera o salga del combate.',submitText:'Retrasar turno',fields:[{name:'target',label:'Esperar al turno de',type:'select',required:true,options:options.map(p=>({value:p.id,label:`${participantName(p)} · iniciativa ${p.initiative??'—'}`}))}]});if(values)command('turn.delay',{targetParticipantId:+values.target})};
function tokensAtCell(c){const tokens=[];for(const o of state.data.objects){const width=Math.max(1,+o.width_cells||1),height=Math.max(1,+o.height_cells||1);if(c.x>=+o.x&&c.x<+o.x+width&&c.y>=+o.y&&c.y<+o.y+height)tokens.push({...o,kind:'OBJECT'})}for(const n of state.data.npcs)if(+n.x===c.x&&+n.y===c.y)tokens.push({...n,kind:'NPC'});for(const p of state.data.players)if((+p.placed||state.user.role==='DM')&&+p.x===c.x&&+p.y===c.y)tokens.push({...p,kind:'PLAYER'});return tokens}
function selectEntitiesInArea(area,additive=false){if(!additive){state.selectedObjects.clear();state.selectedNpcs.clear()}for(const object of state.data.objects){const x=+object.x,y=+object.y,w=Math.max(1,+object.width_cells||1),h=Math.max(1,+object.height_cells||1);if(x<area.x+area.widthCells&&x+w>area.x&&y<area.y+area.heightCells&&y+h>area.y)state.selectedObjects.add(+object.id)}for(const npc of state.data.npcs)if(+npc.x>=area.x&&+npc.x<area.x+area.widthCells&&+npc.y>=area.y&&+npc.y<area.y+area.heightCells)state.selectedNpcs.add(+npc.id);renderEntitySelection();draw()}
function selectMapEntity(entity,additive=false){if(state.user.role==='DM'&&['OBJECT','NPC'].includes(entity.kind)){const id=+entity.id,set=entity.kind==='OBJECT'?state.selectedObjects:state.selectedNpcs;if(!additive){state.selectedObjects.clear();state.selectedNpcs.clear();set.add(id)}else if(set.has(id))set.delete(id);else set.add(id);renderEntitySelection();draw();return}clearEntitySelection(false);inspect(entity)}
function clearEntitySelection(resetInspector=true){state.selectedObjects.clear();state.selectedNpcs.clear();draw();if(resetInspector)$('#inspector').innerHTML='<h2>Selección</h2><p class="muted">Toca un token para inspeccionarlo.</p>'}
function selectionItems(){const items=[];state.selectedObjects=new Set([...state.selectedObjects].filter(id=>state.data.objects.some(o=>+o.id===id)));state.selectedNpcs=new Set([...state.selectedNpcs].filter(id=>state.data.npcs.some(n=>+n.id===id)));for(const id of state.selectedObjects){const entity=state.data.objects.find(o=>+o.id===id);if(entity)items.push({...entity,kind:'OBJECT'})}for(const id of state.selectedNpcs){const entity=state.data.npcs.find(n=>+n.id===id);if(entity)items.push({...entity,kind:'NPC'})}return items}
function selectionCount(){return state.selectedObjects.size+state.selectedNpcs.size}
function renderEntitySelection(){const items=selectionItems();if(!items.length){clearEntitySelection();return}if(items.length===1){inspect(items[0]);return}const objectCount=items.filter(x=>x.kind==='OBJECT').length,npcCount=items.filter(x=>x.kind==='NPC').length,refs=items.map(x=>({kind:x.kind,id:+x.id})),i=$('#inspector'),summary=[objectCount&&`${objectCount} objeto${objectCount===1?'':'s'}`,npcCount&&`${npcCount} personaje${npcCount===1?'':'s'}`].filter(Boolean).join(' y ');i.innerHTML=`<h2>Selección múltiple</h2><div class="token-card"><strong>${summary}</strong><p class="muted">${items.map(x=>esc(x.name)).join(', ')}</p><div class="row"><button id="bulk-show">Hacer visibles</button><button id="bulk-hide">Ocultar</button><button id="bulk-image">Imagen común…</button><button id="bulk-delete" class="danger-action">Eliminar</button><button id="bulk-clear">Limpiar selección</button></div></div>`;i.scrollTop=0;$('#bulk-show').onclick=()=>command('tokens.bulk_update',{items:refs,visible:true});$('#bulk-hide').onclick=()=>command('tokens.bulk_update',{items:refs,visible:false});$('#bulk-image').onclick=()=>{uploadTarget={bulkItems:refs};$('#image-file').click()};$('#bulk-delete').onclick=()=>{if(!confirm(`¿Eliminar ${items.length} tokens seleccionados del mapa?`))return;command('tokens.delete',{items:refs});clearEntitySelection()};$('#bulk-clear').onclick=()=>clearEntitySelection()}
function showCellMenu(tokens,x,y,additive=false){const menu=$('#cell-menu');menu.innerHTML='';tokens.forEach(t=>{const b=document.createElement('button');b.textContent=`${t.kind==='OBJECT'?'■':'●'} ${t.name||t.user_name}`;b.onclick=()=>{menu.hidden=true;selectMapEntity(t,additive)};menu.append(b)});menu.style.left=Math.min(x,canvas.clientWidth-290)+'px';menu.style.top=Math.min(y,canvas.clientHeight-220)+'px';menu.hidden=false}
function inspect(t){const i=$('#inspector');let html=`<h2>Selección</h2><div class="token-card"><strong>${esc(t.name||t.user_name)}</strong><p>${esc(t.kind)}</p>`;if(t.health!==undefined)html+=`<label>Vida<input id="inspect-hp" type="number" value="${+t.health}"></label>`;if(t.kind==='NPC'&&state.user.role==='DM')html+=`<label>Clase de armadura<input id="inspect-ac" type="number" value="${t.armor_class??''}" placeholder="Sin CA"></label>`;if(t.initiative!==undefined)html+=`<label>Iniciativa<input id="inspect-init" type="number" value="${t.initiative??''}"></label>`;if(t.kind==='PLAYER'&&state.user.role==='DM')html+=`<label>Notas privadas del jugador<textarea id="inspect-player-notes" rows="6">${esc(t.dm_notes||'')}</textarea></label>`;if(t.kind!=='PLAYER'&&state.user.role==='DM')html+=`<label>Nombre<input id="inspect-name" value="${esc(t.name||'')}"></label><label>Notas privadas<textarea id="inspect-notes" rows="6">${esc(t.notes||'')}</textarea></label>`;if(t.kind==='OBJECT'&&state.user.role==='DM')html+=`<div class="row"><label>Ancho (casillas)<input id="inspect-width" type="number" min="1" max="${+state.data.scenario.width-(+t.x)}" value="${+t.width_cells||1}"></label><label>Alto (casillas)<input id="inspect-height" type="number" min="1" max="${+state.data.scenario.height-(+t.y)}" value="${+t.height_cells||1}"></label></div><label class="check-field"><input id="inspect-visible" type="checkbox" ${+t.visible?'checked':''}><span>Visible para los jugadores <small>· guardado automático</small></span></label><p class="muted">Tamaño visual: ${Math.max(.25,(+t.width_cells||1)-.75)} × ${Math.max(.25,(+t.height_cells||1)-.75)} casillas.</p>`;if(t.kind==='NPC'&&state.user.role==='DM')html+=`<label class="check-field"><input id="inspect-visible" type="checkbox" ${+t.visible?'checked':''}><span>Visible para los jugadores <small>· guardado automático</small></span></label>`;if(state.user.role==='DM')html+='<button id="inspect-save">Guardar</button> <button id="inspect-move">Mover aquí…</button> '+(t.kind!=='PLAYER'?'<button id="inspect-image">Imagen…</button> <button id="inspect-delete" class="danger-action">Eliminar</button>':'');html+='</div>';i.innerHTML=html;i.scrollTop=0;if(state.user.role==='DM'){if($('#inspect-visible'))$('#inspect-visible').onchange=e=>command('token.update',{kind:t.kind,id:+t.id,visible:e.target.checked});$('#inspect-save').onclick=()=>{if($('#inspect-hp'))command('health.set',{kind:t.kind,id:+t.id,health:+$('#inspect-hp').value});if($('#inspect-init'))command('initiative.set',{kind:t.kind,id:+t.id,initiative:$('#inspect-init').value===''?null:+$('#inspect-init').value});if(t.kind!=='PLAYER'){const changes={kind:t.kind,id:+t.id,name:$('#inspect-name').value,notes:$('#inspect-notes').value};if(t.kind==='OBJECT'){changes.width_cells=+$('#inspect-width').value;changes.height_cells=+$('#inspect-height').value;changes.visible=$('#inspect-visible').checked}else if(t.kind==='NPC'){changes.visible=$('#inspect-visible').checked;changes.armor_class=$('#inspect-ac').value===''?null:+$('#inspect-ac').value}command('token.update',changes)}else command('player.note',{playerId:+t.user_id,notes:$('#inspect-player-notes').value})};$('#inspect-move').onclick=()=>{setMode('select');state.moveToken=t;toast('Toca la casilla de destino')};if($('#inspect-image'))$('#inspect-image').onclick=()=>{uploadTarget={kind:t.kind,id:+t.id};$('#image-file').click()};if($('#inspect-delete'))$('#inspect-delete').onclick=()=>{if(!confirm(`¿Eliminar ${t.kind==='NPC'?'este NPC':'este objeto'} del mapa?`))return;command('token.delete',{kind:t.kind,id:+t.id});state.selectedObjects.delete(+t.id);state.selectedNpcs.delete(+t.id);clearEntitySelection()}}}
function participantName(p){if(p.actor_type==='PLAYER'){const x=state.data.players.find(v=>+v.id===+p.actor_id);return x?.name||x?.user_name||'Jugador'}const x=state.data.npcs.find(v=>+v.id===+p.actor_id);return x?.name||'NPC'}
function esc(s){return String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
start().catch(e=>toast(e.message));
